<?php
declare(strict_types=1);
namespace App\Core\System;
use PDO;
final readonly class HealthRepository{public function __construct(private PDO $pdo){} public function listDefinitionsWithLastResult(int $limit=100): array {$sql="SELECT d.id,d.code,d.name,d.description,d.check_type,d.target,d.interval_seconds,d.timeout_seconds,d.status,d.created_at,d.updated_at,r.status AS last_result_status,r.checked_at AS last_checked_at,r.message AS last_result_message,r.response_time_ms AS last_response_time_ms FROM system_health_check_definitions d LEFT JOIN system_health_check_results r ON r.id=(SELECT r2.id FROM system_health_check_results r2 WHERE r2.health_check_id=d.id ORDER BY r2.checked_at DESC,r2.id DESC LIMIT 1) ORDER BY d.id DESC LIMIT :limit"; $stmt=$this->pdo->prepare($sql); $stmt->bindValue(':limit',$limit,PDO::PARAM_INT); $stmt->execute(); return $stmt->fetchAll(PDO::FETCH_ASSOC)?:[];} public function findDefinitionById(int $id): ?array {$stmt=$this->pdo->prepare('SELECT id,code,name,description,check_type,target,interval_seconds,timeout_seconds,status,created_at,updated_at FROM system_health_check_definitions WHERE id=:id LIMIT 1'); $stmt->execute([':id'=>$id]); $row=$stmt->fetch(PDO::FETCH_ASSOC); return is_array($row)?$row:null;} public function insertResult(int $healthCheckId,string $status,int $responseTimeMs,string $message): bool {$stmt=$this->pdo->prepare('INSERT INTO system_health_check_results (health_check_id,status,response_time_ms,message,checked_at,created_at) VALUES (:health_check_id,:status,:response_time_ms,:message,NOW(),NOW())'); return $stmt->execute([':health_check_id'=>$healthCheckId,':status'=>$status,':response_time_ms'=>$responseTimeMs,':message'=>$message]);}}
